static __attribute__((target("avx2,fma"))) void
radix3_n1_ovs_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, size_t ovs)
{
    /* n1_ovs: butterfly -> tbuf, then scatter all 3 bins via AVX2 extract */
    /* R=3 is not divisible by 4, so no 4x4 transpose is possible. */
    __attribute__((aligned(32))) double tbuf_re[12];
    __attribute__((aligned(32))) double tbuf_im[12];
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS    = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t k = 0; k < vl; k += 4) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);

        /* DFT-3 butterfly [fwd] */
        __m256d ar=_mm256_add_pd(x1_re,x2_re), ai=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d R1r=_mm256_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm256_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm256_add_pd(x0_re,ar); x0_im=_mm256_add_pd(x0_im,ai);
        x1_re=_mm256_fmadd_pd(KS,di,R1r); x1_im=_mm256_fnmadd_pd(KS,dr,R1i);
        x2_re=_mm256_fnmadd_pd(KS,di,R1r); x2_im=_mm256_fmadd_pd(KS,dr,R1i);

        ST(&tbuf_re[0*4], x0_re);
        ST(&tbuf_im[0*4], x0_im);
        ST(&tbuf_re[1*4], x1_re);
        ST(&tbuf_im[1*4], x1_im);
        ST(&tbuf_re[2*4], x2_re);
        ST(&tbuf_im[2*4], x2_im);
        /* Bin 0: extract from tbuf -> scatter */
        { __m256d v=LD(&tbuf_re[0*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_re[(k+0)*ovs+os*0], lo);
          _mm_storeh_pd(&out_re[(k+1)*ovs+os*0], lo);
          _mm_storel_pd(&out_re[(k+2)*ovs+os*0], hi);
          _mm_storeh_pd(&out_re[(k+3)*ovs+os*0], hi); }
        { __m256d v=LD(&tbuf_im[0*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_im[(k+0)*ovs+os*0], lo);
          _mm_storeh_pd(&out_im[(k+1)*ovs+os*0], lo);
          _mm_storel_pd(&out_im[(k+2)*ovs+os*0], hi);
          _mm_storeh_pd(&out_im[(k+3)*ovs+os*0], hi); }
        /* Bin 1: extract from tbuf -> scatter */
        { __m256d v=LD(&tbuf_re[1*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_re[(k+0)*ovs+os*1], lo);
          _mm_storeh_pd(&out_re[(k+1)*ovs+os*1], lo);
          _mm_storel_pd(&out_re[(k+2)*ovs+os*1], hi);
          _mm_storeh_pd(&out_re[(k+3)*ovs+os*1], hi); }
        { __m256d v=LD(&tbuf_im[1*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_im[(k+0)*ovs+os*1], lo);
          _mm_storeh_pd(&out_im[(k+1)*ovs+os*1], lo);
          _mm_storel_pd(&out_im[(k+2)*ovs+os*1], hi);
          _mm_storeh_pd(&out_im[(k+3)*ovs+os*1], hi); }
        /* Bin 2: extract from tbuf -> scatter */
        { __m256d v=LD(&tbuf_re[2*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_re[(k+0)*ovs+os*2], lo);
          _mm_storeh_pd(&out_re[(k+1)*ovs+os*2], lo);
          _mm_storel_pd(&out_re[(k+2)*ovs+os*2], hi);
          _mm_storeh_pd(&out_re[(k+3)*ovs+os*2], hi); }
        { __m256d v=LD(&tbuf_im[2*4]);
          __m128d lo=_mm256_castpd256_pd128(v), hi=_mm256_extractf128_pd(v,1);
          _mm_storel_pd(&out_im[(k+0)*ovs+os*2], lo);
          _mm_storeh_pd(&out_im[(k+1)*ovs+os*2], lo);
          _mm_storel_pd(&out_im[(k+2)*ovs+os*2], hi);
          _mm_storeh_pd(&out_im[(k+3)*ovs+os*2], hi); }
    }
}

